  ('aboriginal-6e11b43e-moex-00452', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-110-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於行政程序法第15條規定之委任，下列敘述何者正確？', '["係上級機關將其權限之一部移轉給下級機關", "關於委任事務之行政訴訟，由委任機關為被告", "上級機關就委任事務不得為指揮、監督", "行政機關得任意為權限之委任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "402", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00453', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-110-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '行政機關對於公務人員之考績辦理程序，下列何者錯誤？', '["各機關對於公務人員之考績，應由主管人員就考績表項目評擬，遞送考績委員會初核，機關長 官核定", "最終送銓敘部銓敘審定", "考績委員會對於擬予考績列丁等及一次記二大過人員，處分前應給予當事人陳述及申辯之機會", "考績委員會對於考績案件，認為有疑義時，得調閱有關考核紀錄及案卷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "402", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
