  ('aboriginal-6e11b43e-moex-00459', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-110-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '有關行政處分與其附款之敘述，下列何者錯誤？', '["行政處分附款為負擔時，得以撤銷訴訟請求撤銷違法之附款", "羈束之授益處分，須有法律授權或為確保許可法定要件之履行，始得為附款", "裁量之授益處分，原則不得添加附款", "行政處分附款之容許性，原則上係依處分具裁量性或羈束性而為不同之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "402", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
